INSERT INTO public.photos VALUES (25559, 'El Pilar a├▒os c.1966', 'Vista del Pilar y el Ebro. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65694300, -0.87852100, '0101000020E6100000C72C7B12D81CECBF062B4EB516D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27418404615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27418404615.webp', 'https://www.flickr.com/photos/zaragozaantigua/27418404615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23766, 'Acampo de Funes 2001', 'Ortofoto del Acampo de Funes, terrenos del t├®rmino municipal de Zaragoza entre Torrecilla de Valmadrid y La Cartuja (que se ve a la derecha). En la parte inferior de la imagen se observa la construcci├│n del pol├¡gono industrial Empresarium. La pr├íctica totalidad del resto del encuadre est├í hoy ocupada por las gigantescas instalaciones del Parque Tecnol├│gico de Reciclado L├│pez Soriano, ubicadas ah├¡ desde 2002. Fuente visual: www.nacionrotonda.com/', 2001, 2001, 2001, 'Siglo XXI', NULL, 41.58616400, -0.83677100, '0101000020E61000000BB8E7F9D3C6EABFD80B056C07CB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25538479172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25538479172.webp', 'https://www.flickr.com/photos/zaragozaantigua/25538479172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25569, 'Arboleda de Macanaz c.1959', 'Imagen capturada desde la arboleda de Macanaz y centrada en una entra├▒able, tipista y folkl├│rica estampa con el fondo del r├¡o Ebro y el Pilar. Resulta de inter├®s el aspecto de la torre del noroeste del templo metropolitano en construcci├│n, denominada de San Francisco de Borja, y luego con car├ícter popular "la del ascensor". Al otro lado de la calle de Florencio Jardiel, antigua del Retiro Alto, vista del progreso edilicio en la manzana n┬║ 6 de la nueva plaza del Pilar, con las traseras de la Hospeder├¡a del Pilar recayente a la plaza, y de los talleres y naves habilitados para el modelado y talla de las esculturas instaladas en la fachada meridional del templo durante las obras de rehabilitaci├│n del templo acometidas en la segunda mitad de los a├▒os cuarenta y primeros a├▒os cincuenta. Estas provisionales construcciones fueron derribadas luego para dar paso a las Casas del Cabildo y el nuevo Colegio de los Infantes.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65890100, -0.87884100, '0101000020E610000034492C29771FECBF9E2633DE56D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48347636107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48347636107.webp', 'https://www.flickr.com/photos/zaragozaantigua/48347636107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25992, 'El Pilar en obras 1945', 'Vista a├®rea del Pilar durante la restauraci├│n de la fachada principal en 1945. Fuente visual de la imagen: Colecci├│n Luis Ariza, en rafaelcastillejo.com', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20085860653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20085860653.webp', 'https://www.flickr.com/photos/zaragozaantigua/20085860653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26053, 'Zaragoza 1899', '"Caesaraugusta". Ilustraci├│n de Francisco de Paula Albi├▒ana (Tarragona, 1841). Fuente: Revista Nuevo Mundo, 1899.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65679000, -0.87853200, '0101000020E6100000C1A90F24EF1CECBF802BD9B111D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32233525914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32233525914.webp', 'https://www.flickr.com/photos/zaragozaantigua/32233525914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21066, 'Plaza del Pilar c.1877', 'Archivo Ruiz-Vernacci. Jean Laurent. Ca. 1874-1877 Zaragoza. La iglesia de Nuestra Se├▒ora del Pilar, vista desde la plaza. Fuente visual: www.mcu.es/fototeca_patrimonio/ImageServlet?accion=41&...', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16059629682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16059629682.webp', 'https://www.flickr.com/photos/zaragozaantigua/16059629682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21084, 'El Pilar 1877', 'Desde mediados del siglo XIX, las grandes familias de la ciudad acometieron su particular revoluci├│n burguesa, conservadora, a la zaragozana, y el espacio urbano fue tambi├®n modificado al efecto. As├¡, se impuls├│ la urbanizaci├│n del Sal├│n de Santa Engracia, y se foment├│ una especial fijaci├│n por la transformaci├│n urbana de la ciudad vieja abriendo rectos viales y ordenando las manzanas de forma regular, especialmente all├¡ donde la operaci├│n estaba asociada a un buen beneficio econ├│mico privado. La ampliaci├│n de la calle de Don Jaime I, por ejemplo. El nomencl├ítor de la ciudad tambi├®n fue objeto de una importante mutaci├│n, eliminando nombres de toda la vida considerados ahora "vulgares", de "dudoso gusto", o "provincianos", para sustituirlos por personajes de los asedios de 1808-1809, as├¡ como pr├│ceres y determinadas eminencias sociales. Esta local "revoluci├│n" necesitaba el respaldo de un nuevo consenso social que legitimara el proceso, el orden resultante, y las estructuras sociales y econ├│micas a ├®l asociadas. El reforzamiento de la ├¡ntima identificaci├│n de la ciudad con el culto pilarista fue piedra angular de esta estrategia, y su impacto urban├¡stico fue tambi├®n notable. A la apertura de la calle de Alfonso I en 1860, le sigui├│ la reforma de la plaza del Pilar dos a├▒os despu├®s, y en 1864 se inici├│ la construcci├│n de la gran c├║pula central pilarista, terminada en 1872. Los inicios del siglo XX ver├¡an nacer y desarrollarse otros interesantes proyectos que reforzaron esta tendencia: el proyecto de la gran plaza del Pilar, iniciado a finales de la d├®cada de los a├▒os treinta, planea ya en 1905. Esta fenomenal captura de Jean Laurent y C┬¬, realizada en altura, desde un solanar a medio camino entre la calle de los Convertidos y la de Alfonso I, ilustra la nueva plaza del Pilar resultante de la reforma de 1862, con sus ├írboles, fuentes, bancos, y quioscos, la reciente y prominente gran c├║pula central, y el estado del templo, con su inacabada y barroca torre de Santiago, ', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65627400, -0.87954800, '0101000020E61000000264E8D84125ECBF899B53C900D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28735376946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28735376946.webp', 'https://www.flickr.com/photos/zaragozaantigua/28735376946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21116, 'Plaza del Pilar c.1880', 'Temprana imagen, desde cierta altura, de la antigua plaza del Pilar, cuando el templo metropolitano manten├¡a la ├║nica torre realizada del proyecto original. Fuente visual: Estudio Coyne (Archivo Municipal de Zaragoza/DARA)', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26261388624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26261388624.webp', 'https://www.flickr.com/photos/zaragozaantigua/26261388624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21123, 'Plaza del Pilar 1889', 'Imagen de la antigua plaza del Pilar capturada desde la rinconera con la calle de Dami├ín Forment, cuando el templo metropolitano manten├¡a la ├║nica e inacabada torre de Santiago del barroco proyecto original. A la derecha, acceso, o retiro, bajo, hacia la ribera o paseo del Ebro.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65606100, -0.87808200, '0101000020E6100000C899266C3F19ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34262340196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34262340196.webp', 'https://www.flickr.com/photos/zaragozaantigua/34262340196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21130, 'Pl. del Pilar c.1880', 'Luminosa imagen parcial capturada en la antigua plaza del Pilar resultante de la reforma que en 1862 le confiri├│ este aspecto de recoleto espacio arbolado con bancos, farolas y quioscos que en invierno, como es el caso, era frecuentado como monumental y tranquila solanera. A la izquierda, la antigua casa de los Aytona. En la parca fachada original del templo metropolitano despunta la ├║nica e incompleta torre de Santiago levantada a principios del siglo XVIII.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65636500, -0.87891900, '0101000020E610000022A81ABD1A20ECBF999EB0C403D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41577698185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41577698185.webp', 'https://www.flickr.com/photos/zaragozaantigua/41577698185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21154, 'Plaza del Pilar 1890', 'Imagen de la plaza del Pilar, con el templo del Pilar previo a la culminaci├│n del remate de la original torre de Santiago del Pilar, en 1892. Fuente visual: Revista Nuevo Mundo, octubre de 1897.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19093740076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19093740076.webp', 'https://www.flickr.com/photos/zaragozaantigua/19093740076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21192, 'Plaza del Pilar c.1890', 'Imagen capturada en la plaza del Pilar y centrada en la salida por la Puerta Baja del hom├│nimo templo de una procesi├│n de can├│nigos portando palmas durante la celebraci├│n del Domingo de Ramos.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65630400, -0.87817600, '0101000020E6100000213A048E041AECBFF31DFCC401D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50122324581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50122324581.webp', 'https://www.flickr.com/photos/zaragozaantigua/50122324581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21202, 'Plaza del Pilar 1894', 'Imagen centrada en la puerta Baja del templo del Pilar antes de la salida de la tradicional procesi├│n que el luminoso d├¡a 12 de octubre y en el marco de las religiosas fiestas en homenaje a la Virgen del Pilar, saliendo del hom├│nimo templo a las 18:00 h. recorri├│ las calles de los Convertidos, Prudencio, la Virgen, Manifestaci├│n, plaza del Mercado, Cerd├ín, Coso, Don Jaime I, plaza de La Seo y regres├│ a la plaza del Pilar. En la fotograf├¡a se recoge, a la izquierda de la puerta, vista del farol correspondiente al primer misterio gozoso denominado ÔÇ£La Anunciaci├│n del Hijo de DiosÔÇØ que fue dise├▒ado por Ricardo Magdalena Tabuenca en 1890 y construido en los talleres de Le├│n Quintana y Bianchi sitos en la calle del Cuatro de Agosto. Asistieron a dicha procesi├│n todas las autoridades, institutos, corporaciones, hermandades y cofrad├¡as de la ciudad, am├®n de los obispos de Lugo, ├üvila, Huesca y auxiliar de Zaragoza, que acompa├▒aron al Nuncio de Su Santidad. Presidi├│ la procesi├│n el Gobernador civil, acompa├▒ado del comandante general, el alcalde y el presidente de la Audiencia provincial.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65623200, -0.87826200, '0101000020E6100000C539EAE8B81AECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54192694198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54192694198.webp', 'https://www.flickr.com/photos/zaragozaantigua/54192694198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21286, 'Plaza del Pilar 1903', 'Imagen desde cierta altura, junto al Pasaje de la Industria y el Comercio, y la calle de Forment, de la antigua plaza del Pilar, cuando perduraba su planta barroca, recogida, acogedora, y una foresta caracterizaba su peculiar espacio interior. A la derecha, junto al ingreso de la original puerta baja del metropolitano templo, han comenzado a montarse los andamios de la obra de culminaci├│n de la segunda torre, la oriental, baja, nueva, o de N┬¬ S┬¬ del Pilar, finalizada en 1907. Al fondo, el antiguo palacio de los Aytona, y el edificio de los Grandes Almacenes del Pilar. Fuente: Fototipia Lucas Escol├í, en www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65643100, -0.87886400, '0101000020E61000003F373465A71FECBF508A56EE05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25935356943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25935356943.webp', 'https://www.flickr.com/photos/zaragozaantigua/25935356943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21290, 'Plaza del Pilar 1903', 'Imagen parcial, capturada desde el punto de vista de un turista accidental, fot├│grafo "amateur", peat├│n impenitente, y adem├ís franc├®s, de la antigua plaza del Pilar, cuando perduraba su planta barroca, acogedora, y una foresta caracterizaba su peculiar y recoleto espacio interior. Situado en el ├íngulo sureste de la plaza, el cuadro de enfoque se centra en la ├║nica torre del templo, su reciente juego de c├║pulas sobre el coro, y la desornamentada fachada, para que luego se diga que lo barroco es siempre sin├│nimo de recargamiento innecesario: ser├ín otros, d├®cadas despu├®s, los que se encarguen de darle su icon├│dulo aspecto "de toda la vida". Lo mismo suceder├í con las "tradicionales" actividades socio-l├║dicas vinculadas en esta plaza con la veneraci├│n de masas en sus distintos formatos: esas cosas, antes, no se hac├¡an. Son contempor├íneas con el aire acondicionado, que estaba siendo inventado por esos primeros a├▒os del XX, y que en los a├▒os 50-60 empez├│ a difundirse masivamente. Tal que igual. Fuente: www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26907155455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26907155455.webp', 'https://www.flickr.com/photos/zaragozaantigua/26907155455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21364, 'Plaza del Pilar 1913', 'Foto: Lorenzo Almarza. Plaza del Pilar desde la bas├¡lica, con la calle Alfonso al fondo a la derecha. Fotograf├¡a tomada el 15 de marzo de 1913. Fuente: Archivo Diputaci├│n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CASCO HIST├ôRICO', 41.65630400, -0.87892200, '0101000020E61000006684B7072120ECBFF31DFCC401D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920293899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920293899.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920293899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21491, 'Los quioscos del Pilar 1923', 'AHPZ. Archivo fotogr├ífico Julio Requejo. 18/03/1923. "Vista del Pilar." A la notable foresta de la plaza acompa├▒aba una interesante cantidad de casetas o quioscos, alguno para aliviar necesidades fisiol├│gicas improrrogables, otros de venta de variados productos de consumo r├ípido. Como toda plaza o espacio abierto com├║n, tambi├®n era susceptible de ser escenario de encuentros m├ís o menos casuales entre personas de distintas orientaciones sexuales. Por eso, era normal la presencia de la "carabina" (como la de primer plano, que escolta a una se├▒orita en el camino de acceso a la puerta principal del templo), como forma de vigilancia militante para garantizar que la decencia y moral hegem├│nica no sufr├¡an quebrantos.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST├ôRICO', 41.65608000, -0.87845500, '0101000020E6100000EA3E00A94D1CECBFA4C7EF6DFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15218934870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15218934870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15218934870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21562, 'Plaza del Pilar c.1925', 'No son legi├│n las im├ígenes de la antigua y barroca plaza del Pilar, mucho menos fotografiada que las de la fachada a la ribera del Ebro. La desnudez clasicista de su lienzo evoca al original muro de cerramiento del templo levantado a principios del siglo XVIII, en un espacio recoleto y minimal, arbolado, e integrado en la trama urbana. Luego vendr├í el espect├ículo de masas. Fuente visual: Archivo Ruiz Vernacci (Fototeca del Patrimonio Hist├│rico, www.mcu.es/)', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65639900, -0.87886400, '0101000020E61000003F373465A71FECBF4510E7E104D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22525437290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22525437290.webp', 'https://www.flickr.com/photos/zaragozaantigua/22525437290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21577, 'Plaza del Pilar c.1920', 'Uno de los quioscos que flanqueaban la v├¡a de acceso a la "puerta baja" de la bas├¡lica del Pilar. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24276746864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24276746864.webp', 'https://www.flickr.com/photos/zaragozaantigua/24276746864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21733, 'Gil Robles 1933', 'A finales del mes de agosto el Pilar fue escenario del enlace matrimonial entre Amalia Casanueva, hija de C├índido Casanueva, diputado en Cortes por el Partido Agrario, y Jos├® Landra de Lara. Asistieron como testigos Jos├® Mar├¡a Gil Robles, diputado en Cortes y referente agrarista estatal que acabada de crear la Confederaci├│n Espa├▒ola de Derechas Aut├│nomas (CEDA); Antonio Royo Villanova, agrarista y diputado en Cortes, al poco Ministro de Marina; y Santiago Guallar Poza, can├│nigo y diputado agrarista en Cortes. Pocos d├¡as despu├®s, Gil Robles asistir├í como observador al primer Congreso de N├║remberg del NSDAP, (titulado "Congreso de la Victoria" tras el "fracaso" de la Rep├║blica de Weimar), para aprender de la did├íctica propaganda nazi. En la imagen, colectivo posado tras la ceremonia religiosa en la puerta del Pilar de familiares, testigos y amigos pol├¡ticos del agrarismo espa├▒ol. A la izquierda, los diputados Guallar, y Gil Robles. En el centro, la novia y el novio junto al diputado Casanueva. A la derecha extrema, el diputado Royo Villanova. Fuente visual: Foto Mar├¡n Chivite, "Nuevo Mundo".', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65627200, -0.87803100, '0101000020E610000040F9BB77D418ECBFE8A38CB800D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21339037974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21339037974.webp', 'https://www.flickr.com/photos/zaragozaantigua/21339037974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21793, 'Pl. del Pilar c.1934', 'Imagen de la esquina oriental de la antigua plaza del Pilar, inmediata a la "Puerta Baja" del templo del Pilar; a la torre Nueva, o de Nuestra Se├▒ora del Pilar de dicho templo; al callej├│n del "Retiro Bajo del Pilar", que conectaba con el paseo del Ebro; y al arranque de la calle del Pilar, al fondo, hacia la derecha. Se trata de uno de esos espacios desaparecidos tras la "remodelaci├│n" de la plaza, unos a├▒os despu├®s. La manzana de edificios de primer plano, entre la plaza del Pilar y la trasera calle de Latassa (antigua de Talamantes), ser├í integralmente demolida, y las viviendas de ambos lados de la calle del Pilar, hasta la Lonja, igual. Se consider├│ que todas las antiguas casonas de esta parte de la ciudad no ten├¡an remedio, y que la mejor forma de "sanear", era derribar. Sic transit gloria Urbis. Fuente visual: Joaqu├¡n Gil Marraco (Cat├ílogo Exposici├│n grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaci├│n de Jos├® Luis Cintora.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65605800, -0.87805700, '0101000020E61000008FC360FE0A19ECBFBC2363B5F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24520610512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24520610512.webp', 'https://www.flickr.com/photos/zaragozaantigua/24520610512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21813, 'Plaza del Pilar 1932', '"Plaza del Pilar y vista parcial", 1932. Imagen de la postal n┬║ 7 de la 2┬¬ serie de la colecci├│n "Rellev" dedicada a Zaragoza, puesta en marcha por J. Codina Torr├ís a principios de la d├®cada de los a├▒os 30 del pasado siglo. Ofrece dos interesantes partes: abajo, fragmento de la plaza del Pilar y de las construcciones que la separaban de la plaza de la Seo; arriba, panorama del casco urbano hacia el este, con la torre de la Magdalena en el centro. Fuente: Ajuntament de Girona, Servei de Gesti├│ Documental, Arxius i Publicacions.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65613800, -0.87824500, '0101000020E610000043041C42951AECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30547671595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30547671595.webp', 'https://www.flickr.com/photos/zaragozaantigua/30547671595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21819, 'Plaza del Pilar 1938', 'Funeral por Jos├® Antonio Primo de Rivera, con su nombre en la bas├¡lica del Pilar, celebrado en noviembre de 1938, dos a├▒os despu├®s de su ocultada muerte. Fuente: www.keecua.com/', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST├ôRICO', 41.65630100, -0.87846800, '0101000020E610000012A452EC681CECBF82AAD1AB01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31509096895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31509096895.webp', 'https://www.flickr.com/photos/zaragozaantigua/31509096895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21891, 'Plaza del Pilar 1939', 'Imagen capturada en la plaza del Pilar y centrada en la cola formada por se├▒oras y se├▒oritas, algunas ataviadas a la antigua, muchas de riguroso luto, esperando para ingresar al hom├│nimo templo durante la festividad del Corpus. Al fondo, fachadas de los inmuebles del lado este de la plaza, que daban continuidad a la calle de Dami├ín Forment, y que poco despu├®s ser├¡an derribados. Entre la arboleda, vista parcial de dos de los quioscos que flanqueaban el ingreso a la Puerta Baja del templo.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65608800, -0.87829400, '0101000020E61000009DBCC804FC1AECBF26A60BB1FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49912995286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49912995286.webp', 'https://www.flickr.com/photos/zaragozaantigua/49912995286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21895, 'Plaza del Pilar 1939', 'Imagen capturada en la plaza del Pilar y centrada en la cola formada por la grey que aguarda para ingresar al hom├│nimo templo durante la festividad del Corpus por la Puerta Baja, que de forma excepcional se muestra sin la decimon├│nica contrapuerta o cancel en madera de nogal que habitualmente oculta los originales y barrocos aderezos que aqu├¡ se muestran al aire.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65629600, -0.87820800, '0101000020E6100000F9BCE2A9471AECBF703FE08101D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50064751296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50064751296.webp', 'https://www.flickr.com/photos/zaragozaantigua/50064751296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21938, 'Guardia Mora 1946', 'Comitiva del dictador Franco a su paso por la calle de Alfonso I, llegando a la plaza del Pilar. Al fondo a la izquierda, la calle de Santiago. A la derecha, la de Prudencio. La Guardia Mora estaba compuesta por soldados marroqu├¡s musulmanes del Ej├®rcito de ├üfrica y que ejerci├│ de escolta de gala del dictador hasta 1que el R├®gimen reconoci├│ la independencia del Reino de Marruecos en 1956.', 1946, 1946, 1946, 'Anos 40', 'CASCO HIST├ôRICO', 41.65596100, -0.87920400, '0101000020E61000007365506D7022ECBFC939B187F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15315831659.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15315831659.webp', 'https://www.flickr.com/photos/zaragozaantigua/15315831659/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21940, 'Ayuntamiento 1946', 'Enero de 1946. Las autoridades, con notable presencia de las religiosas en la imagen, asisten a la ceremonia de colocaci├│n de la primera piedra del nuevo edificio del Ayuntamiento de Zaragoza en la plaza del Pilar 18. No ser├í inaugurado hasta 1965, tras dos d├®cadas de obras. Fuente: www.facebook.com/photo.php?fbid=842175925805034&set=o...', 1946, 1946, 1946, 'Anos 40', 'CASCO HIST├ôRICO', 41.65617600, -0.87724100, '0101000020E610000013BBB6B75B12ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15596914398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15596914398.webp', 'https://www.flickr.com/photos/zaragozaantigua/15596914398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21999, 'Plaza del Pilar 1944', 'Imagen capturada en el entorno de la antigua y arbolada plaza del Pilar, en las inmediaciones de la puerta "Baja" y los quioscos que flanqueaban su acceso. La fotograf├¡a se ha realizado desde el solar de la desaparecida manzana entre la plaza, y la calle de Latassa, derribada durante el proceso de ampliar la plaza, por el este, hasta la calle de Don Jaime I. La fachada sur del Pilar presenta el pr├¡stino y sobrio aspecto original. Fuente visual: foto Casas Torras, en www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'CASCO HIST├ôRICO', 41.65613800, -0.87824500, '0101000020E610000043041C42951AECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33631073801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33631073801.webp', 'https://www.flickr.com/photos/zaragozaantigua/33631073801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22003, 'A├®rodromo Sanjurjo 1941', 'Imagen promocional del Aero Club Zaragoza en su nueva ubicaci├│n del aer├│dromo Sanjurjo, con dos de los cuatro aparatos con que contaba en esas fechas, dos RWD-13 adquiridos como material de guerra por la aviaci├│n nacionalista a la entonces independiente Polonia, y transferidos en 1940 al Aero Club Zaragoza en su resurgimiento tras la guerra. Con la presidencia de Luis Baselga de Yarza, este club funcionaba como Escuela Oficial de pilotos civiles. Fuente visual: "Arag├│n: revista gr├ífica de cultura aragonesa".', 1941, 1941, 1941, 'Anos 40', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34640175246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34640175246.webp', 'https://www.flickr.com/photos/zaragozaantigua/34640175246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22024, 'Calle del Pilar 1941', 'Imagen capturada en la recoleta calle del Pilar con una vista s├│lo posible tras el derribo de las manzanas de viviendas comprendidas a espaldas del fot├│grafo entre la plaza del Pilar y las calles de Latassa y Bayeu, que permite esta panor├ímica desde el extremo m├ís sure├▒o del templo del Pilar, donde en la c├║pula de la capilla de la Virgen destaca el fonograma tra├¡do desde la Alemania nazi con la tradicionalista jaculatoria "Bendita y alabada sea" y etc, e instalado con motivo del 19 centenario de la "llegada de la Virgen". A continuaci├│n, el Retiro Bajo, y el primer gran tramo de los inmuebles impares de la calle del Pilar, comprendido entre los n├║meros 3 y 15. En este ├║ltimo se encontraba la tienda de alimentaci├│n "Casa Delatas", vecina a la gran casa que fuera de los marqueses de Ayerbe, cuya verja de su ingreso principal se destaca en primer t├®rmino. Poco despu├®s todos estos edificios ser├¡an derribados para construir el edificio de la nueva Casa Consistorial.', 1941, 1941, 1941, 'Anos 40', 'CASCO HIST├ôRICO', 41.65604000, -0.87761800, '0101000020E610000090300C587215ECBF156F641EF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50147039346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50147039346.webp', 'https://www.flickr.com/photos/zaragozaantigua/50147039346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22031, 'Calle de Alfonso I 1944', 'Imagen capturada en la calle de Alfonso I durante la cuarta salida de la comparsa de Gigantes y Cabezudos programada en las Fiestas del Pilar. Viniendo desde la Hospeder├¡a del Pilar, la festiva procesionaria se encamina hacia la calle de la Manifestaci├│n. Sobre el "Torero" pende una recordatorio de la IV Feria Nacional de Muestras. Al fondo, la tradicional fachada del templo del Pilar, antes del inicio de las obras de reforma que la mantuvieron andamiada unos cuantos a├▒os.', 1944, 1944, 1944, 'Anos 40', 'CASCO HIST├ôRICO', 41.65613600, -0.87928100, '0101000020E61000004AD05FE81123ECBF37DDB243FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51708340745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51708340745.webp', 'https://www.flickr.com/photos/zaragozaantigua/51708340745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22060, 'Paisano Franco 1953', 'Ayuntamiento de Zaragoza/Mar├¡n Chivite. 21 de junio 1953. Visita de Francisco Franco a Zaragoza. Imagen a la salida de rendir homenaje a la patrona de la Hispanidad en el Templo del Pilar. A su lado, el Alcalde de la ciudad entre 1949 y 1954, Jos├® Mar├¡a Garc├¡a-Belenguer y Garcia, del partido "Movimiento Nacional".', 1953, 1953, 1953, 'Anos 50', 'CASCO HIST├ôRICO', 41.65624800, -0.87813900, '0101000020E6100000D8F2CAF5B619ECBF5F0839EFFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938046145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938046145.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938046145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22062, 'Gran Plaza del Pilar 1954', 'AHPZ. Archivo Coyne. Manuel Coyne. "Plaza del Pilar". Perdura la huella de las manzanas de edificios derribadas para mayor gloria del espacio abierto desde las murallas hasta la Seo. El nuevo Ayuntamiento sigue en obras.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65595200, -0.87817600, '0101000020E6100000213A048E041AECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15027632141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15027632141.webp', 'https://www.flickr.com/photos/zaragozaantigua/15027632141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22086, 'Infantes Reales en plaza del Pilar 1950', 'Juan de Borb├│n, cabeza de la Casa Real espa├▒ola, y la princesa Mar├¡a de las Mercedes de Borb├│n-Dos Sicilias tuvieron dos hijas y dos hijos. Juan Carlos y Alfonso nacieron en Roma (Rep├║blica de Italia), ciudad en la que se hallaban exiliados. Tras unos a├▒os en Lausana (Rep├║blica de Suiza), en 1946 la familia se estableci├│ en Estoril (Rep├║blica de Portugal). En 1950, Alfonso y Juan Carlos fueron enviados a estudiar al Reino de Espa├▒a, al colegio instalado en el Palacio de Miramar (San Sebasti├ín), antigua residencia de verano de la Familia Real. Desde all├¡, realizaron algunos viajes a ciudades como Valencia, Madrid, Sevilla... y Zaragoza. En la imagen, llegada de los infantes Juan Carlos (13 a├▒os de edad) y Alfonso de Borb├│n (10 a├▒os de edad) a la plaza del Pilar, para visitar la bas├¡lica concatedral, en octubre de 1951. Juan Carlos ha descendido ya del coche, y est├í a punto de hacerlo su hermano. Detr├ís de los infantes, imagen de la obra del nuevo edificio que ser├í la sede del Gobernador Civil. Al fondo, a la izquierda, apenas visible a contraluz, la torre de la Seo.', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST├ôRICO', 41.65607000, -0.87830700, '0101000020E6100000C4211B48171BECBF80F10C1AFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16741759737.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16741759737.webp', 'https://www.flickr.com/photos/zaragozaantigua/16741759737/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22102, 'Pl. del Pilar 1954', 'Desde la torre de la Seo, posiblemente en el tercer cuerpo, vista en altura de la nueva plaza de las Catedrales como sumatorio de las antiguas plazas del Pilar y de Huesca para convertirse en escenario de multitudinarias ceremonias de reafirmaci├│n del r├®gimen franquista. En primer t├®rmino y a la izquierda, obras en progresi├│n del Gobierno civil y a la derecha las del ayuntamiento, en este caso con especial desarrollo en la fachada recayente a la plaza. Las dos nuevas torres del Pilar, patrocinadas econ├│micamente por Francisco Urzaiz y Leonor Sala, todav├¡a parecen ascender en sinton├¡a, y la fachada sur del templo ya presenta su nuevo aspecto escult├│rico resultante tras la reforma proyectada por Teodoro R├¡os Balaguer. Fuente: rafaelcastillejo.com', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20523007218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20523007218.webp', 'https://www.flickr.com/photos/zaragozaantigua/20523007218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22148, 'Plaza del Pilar 1951', 'Uno de los ├║ltimos veranos de los jardines, ├írboles y bancos de la antigua plaza del Pilar, y tambi├®n de los quioscos que flanqueaban el ingreso a la puerta Baja del templo metropolitano. Al fondo, despejada vista de la torre de la Seo tras el derribo de las manzanas de viviendas de la antigua calle de Latassa y de los tramos finales de las calles de Forment y de Bayeu. A la izquierda, la arboleda impide ver las obras del nuevo ayuntamiento. A la derecha despuntan iluminados los ca├▒izos y andamios del nuevo Gobierno civil en construcci├│n, y abajo, entre sombras, los muretes tras los que se estaba derribando la manzana de casas entre la plaza y la calle de Goicoechea. Fuente visual: www.ebay.es/', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26638300090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26638300090.webp', 'https://www.flickr.com/photos/zaragozaantigua/26638300090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22153, 'El Pilar 1951', 'Aspecto de la fachada del Pilar, cubierta por andamios durante sus obras de restauraci├│n. Fuente: Revista La Cadiera.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65657400, -0.87932600, '0101000020E61000004AB890477023ECBFB3B3E89D0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28979829518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28979829518.webp', 'https://www.flickr.com/photos/zaragozaantigua/28979829518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22172, 'Pl. del Pilar 1958', 'Imagen capturada durante los ceremoniales oficiales programados con motivo del traslado de los restos mortales de Jos├® Rebolledo de Palafox y Melci al selecto carneario de la bas├¡lica del Pilar. Mientras la procesionaria se encamina al templo por la puerta "alta", el fot├│grafo nos regala una ins├│lita visual, al fondo, del antiguo emboque a la calle de los Convertidos, con el antiguo edificio del n┬║ 30 de la plaza, a la izquierda, y una m├ís extraordinaria vista de algunos edificios de la calle de las Danzas, a la derecha (posiblemente, el n┬║ 20, y el 22), pues la antigua manzana entre la plaza del Pilar, y la calle de las Danzas ya hab├¡a sido derribada para ajustar perfectamente el regular perfil de la nueva y gran plaza del Pilar. y para poder construir en esa ubicaci├│n los nuevos edificios de los juzgados de la ciudad. La manzana entre la calle de las Danzas, y la calle de Prudencio, perdurar├¡a hasta su postrer derribo, m├ís adelante, al objeto de ampliar los edificios de los juzgados. As├¡ desapareci├│ una de las calles m├ís antiguas de la ciudad. Fuente visual: foto ALPI, AMZ.', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST├ôRICO', 41.65627400, -0.87954800, '0101000020E61000000264E8D84125ECBF899B53C900D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31456685226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31456685226.webp', 'https://www.flickr.com/photos/zaragozaantigua/31456685226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22178, 'Pl. del Pilar 1954', 'Eucarist├¡a vespertina celebrada en la plaza del Pilar, con motivo del Congreso Mariano Nacional, celebrado en octubre de 1954. Fuente: foto Mar├¡n Chivite, en HA.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65647400, -0.87906000, '0101000020E6100000A818E76F4221ECBF50560C5707D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31616241272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31616241272.webp', 'https://www.flickr.com/photos/zaragozaantigua/31616241272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22190, 'Plaza del Pilar 1954', 'Tractor durante las obras de la plaza del Pilar y su entorno en 1954. A la izquierda, andamios en el Ayuntamiento en construcci├│n. Al fondo, la torre de la Seo. Fuente: Heraldo.es', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65613800, -0.87824500, '0101000020E610000043041C42951AECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32232564354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32232564354.webp', 'https://www.flickr.com/photos/zaragozaantigua/32232564354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22355, 'Plaza del Pilar c.1962', 'Plaza del Pilar. Fuente: rafaelcastillejo.com', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST├ôRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20708306485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20708306485.webp', 'https://www.flickr.com/photos/zaragozaantigua/20708306485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22369, 'Majorettes 1969', 'Primer desfile del grupo de majorettes de Zaragoza, durante el preg├│n de las fiestas del Pilar, el 11 de octubre de 1969. A la derecha, puerta del Ayuntamiento.', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65599000, -0.87759800, '0101000020E6100000C91EA1664815ECBF6440F67AF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21547340246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21547340246.webp', 'https://www.flickr.com/photos/zaragozaantigua/21547340246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22455, 'Zaragoza 1965', 'Representaci├│n escult├│rica esquem├ítica de la ciudad de Zaragoza, sostenida en sus manos por el "├üngel de la Ciudad", o ├üngel Custodio, obra de Pablo Serrano que forma parte de un conjunto de dos (la otra es San Valero). Flanquean la entrada del Ayuntamiento en la plaza del Pilar, y fueron encargadas por ├®ste en 1964 y colocadas en 1965. Fuente: Wikipedia.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65598000, -0.87755600, '0101000020E61000000E130D52F014ECBF406A1327F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31618605092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31618605092.webp', 'https://www.flickr.com/photos/zaragozaantigua/31618605092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22574, 'Calle de Alfonso I 1973', 'C├®sar S├ínchez V├ízquez. 1973. Calle de Alfonso I, en imagen capturada desde su embocadura en la plaza del Pilar. Destacan las farolas tridentinas instaladas en 1972. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/792846500...', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65604800, -0.87909800, '0101000020E61000000954FF209221ECBF984D8061F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15413572678.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15413572678.webp', 'https://www.flickr.com/photos/zaragozaantigua/15413572678/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22689, 'Plaza del Pilar c.1972', 'Imagen tomada desde una plaza del Pilar poblada de veh├¡culos a motor ante el Ayuntamiento y ajardinada, con la t├¡pica imagen de las palomas arremolinadas en torno a quienes les arrojaban comida. Al fondo, la Lonja y la catedral de San Salvador, m├ís conocida como la Seo, con su esbelta torre barroca. Este entorno fue muy remodelado en la gran intervenci├│n de 1991.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65606100, -0.87811400, '0101000020E61000009F1C05888219ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26812388113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26812388113.webp', 'https://www.flickr.com/photos/zaragozaantigua/26812388113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22690, 'Pl. del Pilar 1970', 'Imagen capturada al atardecer y centrada en el antiguo ingreso del Retiro Bajo de la bas├¡lica de Nuestra Se├▒ora del Pilar, tal como reza la l├ípida adosada a la derecha, a├▒os m├ís tarde sustituida por una nueva ya con la superlativa categor├¡a de "bas├¡lica catedral". Esta puerta de toda la vida fue realizada en 1849 en madera por el escultor bilbilitano Jos├® Alegre, que tall├│ los relieves , y el carpintero Manuel Sarte. Dos peque├▒os maceteros flanquean el ingreso, cuyas puertas de madera presentan una tonalidad bien acorde, y el intrad├│s del arco de medio punto ignora el farol que a├▒os despu├®s le ser├¡a colocado. Una persona se viene y otra se va, y nosotros nos iremos, y no volveremos m├ís. Fuente visual: www.flickr.com/photos/152234007@N06/35072130063/in/album-...', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65631700, -0.87825100, '0101000020E6100000CBBC55D7A11AECBF8867093202D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26873394447.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26873394447.webp', 'https://www.flickr.com/photos/zaragozaantigua/26873394447/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22860, 'Desde San Nicol├ís al Pilar 1987', 'Luis M├¡nguez. 1987. Desde la barroca torrecilla de San Nicol├ís de Bari (convertida en 1902 en iglesia monacal de las Comendadoras Canonesas del Santo Sepulcro), una visual hasta la bas├¡lica del Pilar. Su modesto tama├▒o hace que la vista sea una sucesi├│n de tejados: los propios del Pilar, con las pol├¡cromas tejas de las c├║pulas menores, y las torres en perspectiva caballera; el de la Lonja, con sus cuatro torrecitas angulares; el torreoncillo del complejo arzobispal; las viviendas de la calle Sepulcro con San Vicente de Pa├║l, y las inmediatas viviendas de la calle Boter├│n, que a├▒os despu├®s ser├ín piqueteadas y convertidas en nuevos bloques habitacionales, en 4 alturas y formas integradas en el entorno.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65652100, -0.87788700, '0101000020E610000075AC527AA617ECBF901150E108D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15650433738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15650433738.webp', 'https://www.flickr.com/photos/zaragozaantigua/15650433738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23771, 'Puente Z-40 2007', 'Foto: Esther Casas. Vista de la construcci├│n del puente de la Z-40 o Cuarto Cintur├│n, en febrero de 2007. Est├í tomada desde la margen izquierda del r├¡o Ebro, en las cercan├¡as de Movera. Al fondo, el pol├¡gono industrial Montemol├¡n, junto a la carretera de Castell├│n. Este puente ser├í inaugurado en junio de 2008. Fuente: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', NULL, 41.63218100, -0.83801200, '0101000020E610000048FAB48AFED0EABF8813984EEBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31385371024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31385371024.webp', 'https://www.flickr.com/photos/zaragozaantigua/31385371024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22954, 'Vista desde el Pilar c.1986', 'Interesante vista capturada en despejada altura desde la torre de San Francisco de Borja del Pilar (la del ascensor), con un interesante panorama del suroeste urbano hasta el entorno de la Romareda. En primer t├®rmino, la pr├¡stina torre de Santiago, erigida en tiempos barrocos. si bien culminada a finales del siglo XIX. Inmediato, a la derecha, uno de los espacios de aparcamiento en superficie entonces habilitados en la plaza del Pilar, en este caso en la zona cercana al "Monumento a los H├®roes y M├írtires de Zaragoza ca├¡dos en la Cruzada de Liberaci├│n 1936-1939". A la izquierda, la calle de Alfonso I. En las traseras de los Juzgados, despejada vista de la alabeada calle de Prudencio por los solares de antiguas viviendas que poco despu├®s ser├¡an utilizados para ampliaci├│n de las dependencias judiciales. Hacia el fondo, diversos jalones edilicios de la moderna ciudad, alcanzando hasta los tremebundos bloques Marvel junto al cauce del r├¡o Huerva y la calle del Arzobispo Morcillo. Fuente visual: foto giuseppedibari, en www.flickr.com', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65657400, -0.87932600, '0101000020E61000004AB890477023ECBFB3B3E89D0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43650658822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43650658822.webp', 'https://www.flickr.com/photos/zaragozaantigua/43650658822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23037, 'Rat├│n Mickey 1994', 'Imagen capturada ante la puerta principal del Ayuntamiento, cuando el alcalde Antonio Gonz├ílez Trivi├▒o entrega p├║blicamente la Llave de Oro de la ciudad de Zaragoza al rat├│n Mickey en marzo de ese a├▒o. Este acto se enmarc├│ en la campa├▒a de promoci├│n del espect├ículo sobre hielo titulado La Bella y la Bestia que la compa├▒├¡a Walt Disney program├│ en Espa├▒a, de forma que Zaragoza (Pabell├│n Municipal Pr├¡ncipe Felipe) fue escogida junto a Barcelona y Madrid como los privilegiados escenarios elegidos para finalizar la gira europea de este espect├ículo. En la escena, un sonriente alcalde ofrece al no menos sonriente personaje del rat├│n Mickey, monarca del entretenimiento familiar, una reproducci├│n de las honor├¡ficas llaves que fueron originalmente entregadas al Deseado rey Fernando VII cuando en 1814 visit├│ Zaragoza.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST├ôRICO', 41.65593600, -0.87757500, '0101000020E6100000BE30992A1815ECBF7022FAB5F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50368117333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50368117333.webp', 'https://www.flickr.com/photos/zaragozaantigua/50368117333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
